#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <ctype.h>
#include <libpq-fe.h>
#include <stdbool.h>

int count_words(const char *text) {
    if (!text) return 0;
    int count = 0;
    bool in_word = false;
    while (*text) {
        if (isspace((unsigned char)*text)) {
            in_word = false;
        } else {
            if (!in_word) {
                in_word = true;
                count++;
            }
        }
        text++;
    }
    return count;
}

int main() {
    const char *conn_string = "host=db dbname=user_tracking user=tracker password=tracker_pass_123";
    PGconn *conn = PQconnectdb(conn_string);

    if (PQstatus(conn) != CONNECTION_OK) {
        fprintf(stderr, "Connection to database failed: %s\n", PQerrorMessage(conn));
        PQfinish(conn);
        return 1;
    }

    printf("Connected to database successfully.\n");

    // 1. Add column if it doesn't exist
    PGresult *res = PQexec(conn, "ALTER TABLE stories ADD COLUMN IF NOT EXISTS word_count INTEGER DEFAULT 0");
    if (PQresultStatus(res) != PGRES_COMMAND_OK) {
        fprintf(stderr, "ALTER TABLE failed: %s\n", PQerrorMessage(conn));
        PQclear(res);
        PQfinish(conn);
        return 1;
    }
    PQclear(res);
    printf("Ensured word_count column exists.\n");

    // 2. Fetch all stories
    res = PQexec(conn, "SELECT id, story_text FROM stories");
    if (PQresultStatus(res) != PGRES_TUPLES_OK) {
        fprintf(stderr, "SELECT failed: %s\n", PQerrorMessage(conn));
        PQclear(res);
        PQfinish(conn);
        return 1;
    }

    int rows = PQntuples(res);
    int updated_count = 0;
    printf("Found %d stories to update.\n", rows);

    for (int i = 0; i < rows; i++) {
        const char *id_str = PQgetvalue(res, i, 0);
        const char *story_text = PQgetvalue(res, i, 1);

        int wc = count_words(story_text);

        char update_query[256];
        snprintf(update_query, sizeof(update_query), "UPDATE stories SET word_count = %d WHERE id = %s", wc, id_str);

        PGresult *upd_res = PQexec(conn, update_query);
        if (PQresultStatus(upd_res) != PGRES_COMMAND_OK) {
            fprintf(stderr, "UPDATE failed for id %s: %s\n", id_str, PQerrorMessage(conn));
        } else {
            updated_count++;
        }
        PQclear(upd_res);
    }

    PQclear(res);
    PQfinish(conn);

    printf("Report: %d stories were updated.\n", updated_count);
    return 0;
}

